// app/articles/[slug]/page.tsx

// Tell Next.js which routes to generate at build time
export async function generateStaticParams() {
  const articles = await articleRepository.listAll()
  return articles.map((article) => ({ slug: article.slug }))
}

export default async function ArticlePage({ params }) {
  const { slug } = params
  const article = await articleRepository.getBySlug(slug)
  if (!article) notFound()

  return <ArticleView article={article} />
}

// Result: 100+ article pages pre-rendered at build time
// Performance: ~50ms response time (CDN cached)

// app/(dashboard)/dashboard/admin/page.tsx

export default async function AdminDashboard() {
  // Runs on EVERY request
  const session = await getServerSession()

  if (!session) {
    redirect('/login')  // Protect with auth
  }

  // Data is user-specific
  const adminData = await getAdminData(session.user.id)

  return <AdminDashboardView data={adminData} />
}

// Result: Page renders fresh on every request
// Performance: ~200-500ms response time (no cache)
// Benefit: Can show personalized data, enforce permissions

// app/news/page.tsx

// Revalidate every hour (3600 seconds)
export const revalidate = 3600

export default async function NewsPage() {
  // Runs at build time, then caches
  // Regenerated every hour automatically
  const data = await getNewsHubData()
  return <FeaturedGrid data={data} />
}

// Result: Page cached for 1 hour, fast CDN delivery
// After 1 hour: next request triggers regeneration
// Performance: ~50ms response time (first hour), ~100ms after revalidation
// Freshness: Updates automatically every hour
